import React, { useCallback, useEffect, useRef, useState } from 'react';
import { analyzeConcept } from '../api/endpoints';
import type { AnalyzeResponse } from '../types/models';

/* ─── Types ─── */

interface ChatMessage {
  id: string;
  role: 'user' | 'ai';
  content: string;
  timestamp: string;
  confidence?: number;
  level?: string;
}

interface ConceptChatProps {
  conceptName: string | null;
  userId: string;
  onNewAnalysis?: (analysis: AnalyzeResponse) => void;
}

/* ─── Main Component ─── */

export const ConceptChat: React.FC<ConceptChatProps> = ({
  conceptName,
  userId,
  onNewAnalysis,
}) => {
  const [histories, setHistories] = useState<Record<string, ChatMessage[]>>({});
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const initializedRef = useRef<Set<string>>(new Set());

  const currentMessages = conceptName ? (histories[conceptName] ?? []) : [];

  /* Auto-send AI greeting when a new concept is inspected */
  useEffect(() => {
    if (!conceptName) return;
    if (initializedRef.current.has(conceptName)) return;
    initializedRef.current.add(conceptName);

    const greeting: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'ai',
      content: `Tell me what you know about **${conceptName}**. Explain it in your own words — I'll give you targeted feedback based on your understanding.`,
      timestamp: new Date().toISOString(),
    };

    setHistories((prev) => ({
      ...prev,
      [conceptName]: [greeting],
    }));
  }, [conceptName]);

  /* Auto-scroll to newest message */
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [currentMessages.length]);

  /* Submit explanation for analysis */
  const handleSubmit = useCallback(async () => {
    if (!conceptName || !input.trim() || loading) return;

    const userText = input.trim();
    const userMsg: ChatMessage = {
      id: crypto.randomUUID(),
      role: 'user',
      content: userText,
      timestamp: new Date().toISOString(),
    };

    setHistories((prev) => ({
      ...prev,
      [conceptName]: [...(prev[conceptName] ?? []), userMsg],
    }));
    setInput('');
    setLoading(true);

    try {
      const result = await analyzeConcept({
        concept: conceptName,
        explanation: userText,
        userId,
      });

      const aiMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'ai',
        content: formatAiResponse(result, conceptName),
        timestamp: new Date().toISOString(),
        confidence: result.confidence,
        level: result.understandingLevel,
      };

      setHistories((prev) => ({
        ...prev,
        [conceptName]: [...(prev[conceptName] ?? []), aiMsg],
      }));

      onNewAnalysis?.(result);
    } catch {
      const errMsg: ChatMessage = {
        id: crypto.randomUUID(),
        role: 'ai',
        content: 'Something went wrong analyzing your explanation. Please try again.',
        timestamp: new Date().toISOString(),
      };
      setHistories((prev) => ({
        ...prev,
        [conceptName]: [...(prev[conceptName] ?? []), errMsg],
      }));
    } finally {
      setLoading(false);
    }
  }, [conceptName, input, loading, userId, onNewAnalysis]);

  /* Don't render when no concept is selected */
  if (!conceptName) return null;

  return (
    <div className="flex flex-col border-t border-surface-border/40">
      {/* Header */}
      <div className="flex items-center justify-between px-4 py-2.5">
        <span className="flex items-center gap-1.5 text-[11px] font-semibold uppercase tracking-wider text-text-faint">
          <svg className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M7.5 8.25h9m-9 3H12m-9.75 1.51c0 1.6 1.123 2.994 2.707 3.227 1.087.16 2.185.283 3.293.369V21l4.076-4.076a1.526 1.526 0 011.037-.443 48.282 48.282 0 005.68-.494c1.584-.233 2.707-1.626 2.707-3.228V6.741c0-1.602-1.123-2.995-2.707-3.228A48.394 48.394 0 0012 3c-2.392 0-4.744.175-7.043.513C3.373 3.746 2.25 5.14 2.25 6.741v6.018z" />
          </svg>
          Concept Chat
        </span>
        <ProgressIndicator messages={currentMessages} />
      </div>

      {/* Messages */}
      <div className="overflow-y-auto px-3 pb-2" style={{ maxHeight: '260px', minHeight: '120px' }}>
        {currentMessages.map((msg) => (
          <div
            key={msg.id}
            className={`mb-2 flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
          >
            <div
              className={`max-w-[85%] rounded-xl px-3 py-2 text-[11px] leading-relaxed ${
                msg.role === 'user'
                  ? 'bg-accent/20 text-accent-light'
                  : 'bg-surface/40 text-text-secondary'
              }`}
            >
              <MessageContent content={msg.content} />
              {msg.confidence !== undefined && (
                <ConfidenceBadge confidence={msg.confidence} level={msg.level} />
              )}
            </div>
          </div>
        ))}

        {/* Typing indicator */}
        {loading && (
          <div className="mb-2 flex justify-start">
            <div className="rounded-xl bg-surface/40 px-3 py-2.5">
              <div className="flex gap-1">
                <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-accent/60" style={{ animationDelay: '0ms' }} />
                <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-accent/60" style={{ animationDelay: '150ms' }} />
                <span className="h-1.5 w-1.5 animate-bounce rounded-full bg-accent/60" style={{ animationDelay: '300ms' }} />
              </div>
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input — pinned at bottom */}
      <div className="flex-shrink-0 border-t border-surface-border/20 p-3">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                handleSubmit();
              }
            }}
            placeholder="Explain this concept..."
            disabled={loading}
            className="flex-1 rounded-lg border border-surface-border/50 bg-surface/30 px-3 py-2 text-xs text-text-primary placeholder-text-faint outline-none transition-colors focus:border-accent/50 focus:ring-1 focus:ring-accent/20 disabled:opacity-50"
          />
          <button
            onClick={handleSubmit}
            disabled={!input.trim() || loading}
            className="flex-shrink-0 rounded-lg bg-accent/20 px-3 py-2 text-xs font-medium text-accent transition-colors hover:bg-accent/30 disabled:cursor-not-allowed disabled:opacity-40"
          >
            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M6 12L3.269 3.126A59.768 59.768 0 0121.485 12 59.77 59.77 0 013.27 20.876L5.999 12zm0 0h7.5" />
            </svg>
          </button>
        </div>
      </div>
    </div>
  );
};

/* ─── Helpers ─── */

/** Format AI response based on confidence threshold */
function formatAiResponse(result: AnalyzeResponse, conceptName: string): string {
  const pct = Math.round(result.confidence * 100);
  const intervention = result.microIntervention;
  const examples = intervention?.content?.examples ?? [];

  // ─── TEACHING MODE: confidence < 30% ───────────────────────────────────
  // The student doesn't know this concept. Switch to structured teaching.
  if (pct < 30) {
    const lines: string[] = [];

    if (pct < 5) {
      lines.push(`**No explanation detected.** Let me introduce you to **${conceptName}**.`);
    } else {
      lines.push(`**${pct}% confidence** — It looks like you're not familiar with **${conceptName}** yet. Let me explain it.`);
    }
    lines.push('');

    // 1️⃣ Simple explanation
    if (result.suggestedExplanation) {
      lines.push(`**What is ${conceptName}?**`);
      lines.push(result.suggestedExplanation);
      lines.push('');
    } else if (intervention?.content?.explanation) {
      lines.push(`**What is ${conceptName}?**`);
      lines.push(intervention.content.explanation);
      lines.push('');
    }

    // 2️⃣ Concrete example
    if (examples.length > 0) {
      lines.push(`**Example:**`);
      lines.push(examples[0]);
      lines.push('');
    }

    // 3️⃣ Analogy (second example acts as analogy/comparison)
    if (examples.length > 1) {
      lines.push(`**Think of it like this:**`);
      lines.push(examples[1]);
      lines.push('');
    }

    // 4️⃣ One follow-up question to activate thinking
    const followUp =
      result.nextQuestion ??
      intervention?.content?.followUpQuestions?.[0];
    if (followUp) {
      lines.push(`**Quick question for you:**`);
      lines.push(followUp);
    }

    return lines.join('\n');
  }

  // ─── IMPROVEMENT MODE: 30–60% ──────────────────────────────────────────
  if (pct < 60) {
    let content = `**${pct}% confidence** — You have a **${result.understandingLevel}**-level grasp of **${conceptName}**. Let's strengthen it.`;

    if (intervention?.content?.explanation) {
      content += `\n\n${intervention.content.explanation}`;
    }
    if (examples.length > 0) {
      content += `\n\n**Example:** ${examples[0]}`;
    }
    if (result.missingConcepts?.length) {
      content += `\n\n**Key gaps:** ${result.missingConcepts.join(', ')}`;
    } else if (result.debtIndicators.length > 0) {
      content += `\n\n**Gaps to address:**\n${result.debtIndicators.map((d) => `• ${d.explanation}`).join('\n')}`;
    }
    const followUp = result.nextQuestion ?? intervention?.content?.followUpQuestions?.[0];
    if (followUp) content += `\n\n→ ${followUp}`;
    content += '\n\nTry explaining again — I track your progress!';
    return content;
  }

  // ─── POSITIVE REINFORCEMENT: >60% ─────────────────────────────────────
  let content = `**${pct}% confidence** — Great job! Your **${result.understandingLevel}**-level understanding of **${conceptName}** is solid.`;

  if (result.debtIndicators.length > 0) {
    content += `\n\n**Areas to strengthen:**\n${result.debtIndicators.map((d) => `• ${d.explanation}`).join('\n')}`;
  }
  if (result.missingConcepts?.length) {
    content += `\n\n**Consider covering:** ${result.missingConcepts.join(', ')}`;
  }
  const followUp = result.nextQuestion ?? intervention?.content?.followUpQuestions?.[0];
  if (followUp) content += `\n\n→ ${followUp}`;
  return content;
}

/* ─── Sub-components ─── */

/** Renders simple markdown: **bold** and newlines */
const MessageContent: React.FC<{ content: string }> = ({ content }) => {
  const parts = content.split(/(\*\*.*?\*\*|\n)/g);
  return (
    <span>
      {parts.map((part, i) => {
        if (part === '\n') return <br key={i} />;
        if (part.startsWith('**') && part.endsWith('**')) {
          return (
            <strong key={i} className="font-semibold text-text-primary">
              {part.slice(2, -2)}
            </strong>
          );
        }
        return <span key={i}>{part}</span>;
      })}
    </span>
  );
};

/** Color-coded confidence bar shown on AI response bubbles */
const ConfidenceBadge: React.FC<{ confidence: number; level?: string }> = ({
  confidence,
  level,
}) => {
  const pct = Math.round(confidence * 100);
  const color =
    confidence >= 0.7 ? '#34D399' : confidence >= 0.4 ? '#FBBF24' : '#F87171';

  return (
    <div className="mt-1.5 flex items-center gap-2">
      <div className="h-1 flex-1 rounded-full bg-white/10">
        <div
          className="h-full rounded-full transition-all duration-500"
          style={{ width: `${pct}%`, background: color }}
        />
      </div>
      <span className="text-[9px] font-bold" style={{ color }}>
        {pct}%
      </span>
      {level && <span className="text-[9px] text-text-faint">{level}</span>}
    </div>
  );
};

/** Header progress dot showing latest confidence */
const ProgressIndicator: React.FC<{ messages: ChatMessage[] }> = ({
  messages,
}) => {
  const aiMessages = messages.filter(
    (m) => m.role === 'ai' && m.confidence !== undefined,
  );
  if (aiMessages.length === 0) return null;

  const latest = aiMessages[aiMessages.length - 1];
  const conf = latest.confidence ?? 0;
  const color = conf >= 0.7 ? '#34D399' : conf >= 0.4 ? '#FBBF24' : '#F87171';

  return (
    <div className="flex items-center gap-1.5">
      <div
        className="h-1.5 w-1.5 rounded-full"
        style={{ background: color }}
      />
      <span className="text-[9px] font-bold" style={{ color }}>
        {Math.round(conf * 100)}%
      </span>
    </div>
  );
};
