/**
 * Knowledge Graph Builder
 *
 * Transforms a flat list of AnalyzeResponse objects into a rich graph
 * with two kinds of nodes:
 *   - "analyzed" nodes: concepts the user has actually analyzed (rich data)
 *   - "satellite" nodes: related/prerequisite concepts returned by AI (stubs)
 *
 * Edges come from three sources:
 *   1. AI-returned relatedConcepts and prerequisites (domain-aware)
 *   2. LLM-generated expansions from /v1/expand-concept (domain-aware)
 *   3. Client-side inference between analyzed concepts
 */

import type { Node, Edge } from '@xyflow/react';
import * as d3 from 'd3';
import type { AnalyzeResponse } from '../types/models';
import type { KnowledgeNodeData } from '../components/ConceptNode';
import { inferRelationships } from './conceptRelationships';

/* ─── Constants ─── */
const ANALYZED_WIDTH = 160;
const ANALYZED_HEIGHT = 160;
const SATELLITE_WIDTH = 100;
const SATELLITE_HEIGHT = 80;

/* ─── Normalization ─── */
function normalize(s: string): string {
  return s.toLowerCase().replace(/[^a-z0-9]/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '');
}

/* ─── Deduplicate: keep latest per concept ─── */
function deduplicateLatest(analyses: AnalyzeResponse[]): AnalyzeResponse[] {
  const map = new Map<string, AnalyzeResponse>();
  for (const a of analyses) {
    const key = normalize(a.conceptId);
    map.set(key, a);
  }
  return Array.from(map.values());
}

/**
 * Determine if an analysis needs LLM concept expansion.
 * True when the AI returned fewer than 3 related concepts.
 */
export function needsExpansion(a: AnalyzeResponse): boolean {
  return (a.relatedConcepts?.length ?? 0) < 3;
}

/**
 * Get concepts to use for satellite node generation.
 * Priority: AI-returned > LLM-generated expansion > empty (no bias)
 */
function getConceptsForNode(
  a: AnalyzeResponse,
  expansions: Record<string, string[]>,
): { related: string[]; prereqs: string[] } {
  const hasAIRelated = (a.relatedConcepts?.length ?? 0) >= 3;
  const hasAIPrereqs = (a.prerequisites?.length ?? 0) >= 2;

  if (hasAIRelated && hasAIPrereqs) {
    return { related: a.relatedConcepts ?? [], prereqs: a.prerequisites ?? [] };
  }

  // Use LLM expansion if available
  const expanded = expansions[a.conceptId] ?? [];
  if (expanded.length > 0) {
    const mid = Math.ceil(expanded.length / 2);
    return {
      related: hasAIRelated ? (a.relatedConcepts ?? []) : expanded.slice(0, mid),
      prereqs: hasAIPrereqs ? (a.prerequisites ?? []) : expanded.slice(mid),
    };
  }

  // Fallback: use whatever the AI returned, even if sparse
  return {
    related: a.relatedConcepts ?? [],
    prereqs: a.prerequisites ?? [],
  };
}

/* ─── Build full knowledge graph ─── */
export interface KnowledgeGraph {
  nodes: Node[];
  edges: Edge[];
  analyzedIds: Set<string>;
}

export function buildKnowledgeGraph(
  allAnalyses: AnalyzeResponse[],
  expansions: Record<string, string[]> = {},
): KnowledgeGraph {
  const unique = deduplicateLatest(allAnalyses);
  const analyzedNormMap = new Map<string, AnalyzeResponse>();
  const analyzedIdSet = new Set<string>();

  for (const a of unique) {
    analyzedNormMap.set(normalize(a.conceptId), a);
    analyzedIdSet.add(a.conceptId);
  }

  // Enrich analyses with LLM-generated or AI-returned concepts
  const enriched = unique.map((a) => {
    const { related, prereqs } = getConceptsForNode(a, expansions);
    return {
      ...a,
      relatedConcepts: related,
      prerequisites: prereqs,
    };
  });

  // Collect satellite concept names from enriched responses
  const satelliteNames = new Map<string, string>();
  for (const a of enriched) {
    for (const rc of a.relatedConcepts ?? []) {
      const norm = normalize(rc);
      if (!analyzedNormMap.has(norm) && !satelliteNames.has(norm)) {
        satelliteNames.set(norm, formatConceptName(rc));
      }
    }
    for (const p of a.prerequisites ?? []) {
      const norm = normalize(p);
      if (!analyzedNormMap.has(norm) && !satelliteNames.has(norm)) {
        satelliteNames.set(norm, formatConceptName(p));
      }
    }
  }

  // Build nodes
  const nodes: Node[] = [];

  // 1. Analyzed nodes
  for (const a of enriched) {
    nodes.push({
      id: a.conceptId,
      type: 'concept',
      position: { x: 0, y: 0 },
      data: {
        label: a.conceptId,
        level: a.understandingLevel,
        confidence: a.confidence,
        debtCount: a.debtIndicators.length,
        nodeKind: 'analyzed',
        relatedCount: (a.relatedConcepts?.length ?? 0) + (a.prerequisites?.length ?? 0),
      } satisfies KnowledgeNodeData,
    });
  }

  // 2. Satellite nodes
  for (const [norm, displayName] of satelliteNames) {
    nodes.push({
      id: `sat_${norm}`,
      type: 'concept',
      position: { x: 0, y: 0 },
      data: {
        label: displayName,
        level: 'surface',
        confidence: 0,
        debtCount: 0,
        nodeKind: 'satellite',
        relatedCount: 0,
      } satisfies KnowledgeNodeData,
    });
  }

  // Build edges
  const edges: Edge[] = [];
  const edgeSeen = new Set<string>();

  function addEdge(source: string, target: string, label: string, kind: 'ai' | 'inferred') {
    const key = `${source}::${target}`;
    const reverseKey = `${target}::${source}`;
    if (edgeSeen.has(key) || edgeSeen.has(reverseKey)) return;
    edgeSeen.add(key);
    const isAI = kind === 'ai';
    edges.push({
      id: `e-${edges.length}`,
      source,
      target,
      label: label !== 'related' ? label : undefined,
      animated: isAI,
      type: 'default',
      style: {
        stroke: isAI ? 'rgba(99,102,241,0.5)' : 'rgba(113,113,122,0.18)',
        strokeWidth: isAI ? 2 : 1,
      },
      labelStyle: {
        fill: 'rgba(161,161,170,0.6)',
        fontSize: 9,
        fontWeight: 500,
      },
    });
  }

  // 3a. Edges from relatedConcepts (AI or fallback-enriched)
  for (const a of enriched) {
    for (const rc of a.relatedConcepts ?? []) {
      const norm = normalize(rc);
      const targetId = analyzedNormMap.has(norm)
        ? analyzedNormMap.get(norm)!.conceptId
        : satelliteNames.has(norm)
          ? `sat_${norm}`
          : null;
      if (targetId && targetId !== a.conceptId) {
        addEdge(a.conceptId, targetId, 'related', 'ai');
      }
    }

    // 3b. Edges from prerequisites
    for (const p of a.prerequisites ?? []) {
      const norm = normalize(p);
      const sourceId = analyzedNormMap.has(norm)
        ? analyzedNormMap.get(norm)!.conceptId
        : satelliteNames.has(norm)
          ? `sat_${norm}`
          : null;
      if (sourceId && sourceId !== a.conceptId) {
        addEdge(sourceId, a.conceptId, 'prerequisite', 'ai');
      }
    }
  }

  // 3c. Client-side inferred edges between analyzed concepts
  const analyzedIds = unique.map((a) => a.conceptId);
  const inferred = inferRelationships(analyzedIds);
  for (const e of inferred) {
    addEdge(e.source, e.target, e.relationship, 'inferred');
  }

  // Apply force-directed layout
  const positioned = applyForceLayout(nodes, edges);

  return {
    nodes: positioned,
    edges,
    analyzedIds: analyzedIdSet,
  };
}

/* ─── D3 Force-Directed Layout ─── */
interface SimNode extends d3.SimulationNodeDatum {
  id: string;
  isSatellite: boolean;
}

function applyForceLayout(nodes: Node[], edges: Edge[]): Node[] {
  if (nodes.length === 0) return nodes;

  // Build simulation nodes
  const simNodes: SimNode[] = nodes.map((n, i) => {
    const isSat = (n.data as KnowledgeNodeData).nodeKind === 'satellite';
    // Spread initial positions in a circle to help convergence
    const angle = (2 * Math.PI * i) / nodes.length;
    const radius = 200 + Math.random() * 100;
    return {
      id: n.id,
      isSatellite: isSat,
      x: Math.cos(angle) * radius,
      y: Math.sin(angle) * radius,
    };
  });

  const nodeMap = new Map(simNodes.map((n) => [n.id, n]));

  // Build simulation links
  const simLinks = edges
    .filter((e) => nodeMap.has(e.source) && nodeMap.has(e.target))
    .map((e) => ({
      source: e.source,
      target: e.target,
    }));

  // Configure and run force simulation
  const simulation = d3
    .forceSimulation<SimNode>(simNodes)
    .force(
      'link',
      d3
        .forceLink<SimNode, { source: string; target: string }>(simLinks)
        .id((d) => d.id)
        .distance(180)
        .strength(0.7),
    )
    .force('charge', d3.forceManyBody<SimNode>().strength(-500))
    .force('center', d3.forceCenter(0, 0))
    .force(
      'collision',
      d3
        .forceCollide<SimNode>()
        .radius((d) => (d.isSatellite ? SATELLITE_WIDTH / 2 + 30 : ANALYZED_WIDTH / 2 + 40)),
    )
    .force('x', d3.forceX<SimNode>(0).strength(0.05))
    .force('y', d3.forceY<SimNode>(0).strength(0.05))
    .stop();

  // Run simulation to completion synchronously (300 ticks is plenty)
  const ticks = Math.max(300, nodes.length * 3);
  simulation.tick(ticks);

  // Map positions back to nodes
  const posMap = new Map(simNodes.map((sn) => [sn.id, { x: sn.x ?? 0, y: sn.y ?? 0 }]));

  return nodes.map((node) => {
    const pos = posMap.get(node.id) ?? { x: 0, y: 0 };
    const isSatellite = (node.data as KnowledgeNodeData).nodeKind === 'satellite';
    const w = isSatellite ? SATELLITE_WIDTH : ANALYZED_WIDTH;
    const h = isSatellite ? SATELLITE_HEIGHT : ANALYZED_HEIGHT;
    return {
      ...node,
      position: {
        x: pos.x - w / 2,
        y: pos.y - h / 2,
      },
    };
  });
}

/* ─── Helpers ─── */
function formatConceptName(raw: string): string {
  return raw
    .replace(/_/g, ' ')
    .replace(/\b\w/g, (c) => c.toUpperCase());
}
