import client from './client';
import type {
  MentalModelGraph,
  EvidenceSubmission,
  EvidenceResponse,
  MicroIntervention,
  AnalyzeRequest,
  AnalyzeResponse,
} from '../types/models';

export const fetchMentalModel = async (
  userId: string
): Promise<MentalModelGraph> => {
  const response = await client.get<MentalModelGraph>(
    `/mental-model/${userId}`
  );
  return response.data;
};

export const submitEvidence = async (
  evidence: EvidenceSubmission
): Promise<EvidenceResponse> => {
  const response = await client.post<EvidenceResponse>('/evidence', evidence);
  return response.data;
};

export const fetchInterventions = async (
  conceptId: string,
  userId: string
): Promise<MicroIntervention[]> => {
  const response = await client.get<MicroIntervention[]>(
    `/interventions/${conceptId}`,
    { params: { userId } }
  );
  return response.data;
};

export const markConceptUnderstood = async (
  userId: string,
  conceptId: string
): Promise<MentalModelGraph> => {
  const response = await client.put<MentalModelGraph>(
    `/mental-model/${userId}/concepts/${conceptId}/understood`
  );
  return response.data;
};

export const analyzeConcept = async (
  request: AnalyzeRequest
): Promise<AnalyzeResponse> => {
  const response = await client.post<AnalyzeResponse>(
    '/v1/analyze',
    request
  );
  return response.data;
};

export interface ExpandConceptResponse {
  concept: string;
  domain: string;
  concepts: string[];
}

/**
 * Call the LLM to generate domain-specific related concepts for a given concept.
 * Used to populate cognitive map satellite nodes dynamically.
 * Returns empty concepts list if the endpoint is unavailable (graceful degradation).
 */
export const expandConcept = async (
  concept: string
): Promise<ExpandConceptResponse> => {
  try {
    const response = await client.post<ExpandConceptResponse>(
      '/v1/expand-concept',
      { concept }
    );
    return response.data;
  } catch {
    // Graceful degradation — endpoint may not be deployed yet
    return { concept, domain: 'general', concepts: [] };
  }
};
